parameters.jsCode:
const items = $input.first().json.text;

let result = '';
for (const item of items) {
  if (item.json?.data?.text) {
    result = item.json.data.text;
    break;
  }
}

// Удаляем все \r, \n, \t, заменяя на пробел
let cleanedText = result.replace(/[\r\n\t]+/g, ' ');

// Заменяем маркеры "•" и точки с пробелом на дефис и пробел
cleanedText = cleanedText.replace(/•/g, '-');

// Убираем лишние пробелы (больше одного подряд)
cleanedText = cleanedText.replace(/ +/g, ' ').trim();

return [
  {
    json: {
      result: cleanedText
    }
  }
];

// Вход: текст из Telegram, например, "Идея1\nИдея2\nИдея3" или "1. Идея1 2. Идея2"
const text = $('Edit Fields').first().json.text// Получаем текст сообщения

// Разделяем по новым строкам (или адаптируй: по ',' или регуляркой для номеров)
let ideas = text.split('\n').map(idea => idea.trim()).filter(idea => idea.length > 0);

// Если идеи нумерованы (типа "1. ..."), используй regex для очистки
// ideas = text.split(/\d+\./).map(idea => idea.trim()).filter(idea => idea.length > 0);
ideas = ideas.map(idea => idea.replace(/^\d+\.\s*/, ''));

// Возвращаем массив объектов, где каждый — отдельная идея
return ideas.map(idea => ({ json: { idea } }));
